  ('dietitian-moex-04553', 'dietitian', 'dietitian-moex-112-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '依據民國102～105年國民營養健康狀況變遷調查六大類食物攝取情形，下列敘述何者錯誤？', '["除7～12歲外，乳品類攝取不足1份者比例高達8成以上", "13～18歲男女性乳品、堅果種子、蔬菜類、水果類距離每日飲食指南建議差距甚大", "13～44歲男性的甜飲料攝取頻率，每日超過1次以上者有50％以上", "45歲以上的甜飲料攝取頻率最低"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:36+00:00", "source_pdf_sha1": "5d38408647b2", "answer_pdf_sha1": "f94dd9c2be8e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "101", "s": "0105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
